import{_ as s,o as n,c as p,ag as e}from"./chunks/framework.BWGJuBbb.js";const u=JSON.parse('{"title":"회의 & 협업 활용법","description":"","frontmatter":{},"headers":[],"relativePath":"guide/meeting.md","filePath":"guide/meeting.md","lastUpdated":1773586478000}'),l={name:"guide/meeting.md"};function t(i,a,c,o,d,h){return n(),p("div",null,[...a[0]||(a[0]=[e(`<h1 id="회의-협업-활용법" tabindex="-1">회의 &amp; 협업 활용법 <a class="header-anchor" href="#회의-협업-활용법" aria-label="Permalink to &quot;회의 &amp; 협업 활용법&quot;">​</a></h1><blockquote><p>회의 전, 회의 중, 회의 후 — Claude가 모든 단계를 도와줍니다.</p></blockquote><h2 id="회의-전-안건-정리" tabindex="-1">회의 전: 안건 정리 <a class="header-anchor" href="#회의-전-안건-정리" aria-label="Permalink to &quot;회의 전: 안건 정리&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>내일 오전 10시 마케팅팀 주간회의 안건을 정리해줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>논의 주제:</span></span>
<span class="line"><span>- 신제품 론칭 캠페인 진행 현황</span></span>
<span class="line"><span>- SNS 광고 성과 리뷰 (지난주 데이터)</span></span>
<span class="line"><span>- 다음 분기 예산 배분</span></span>
<span class="line"><span>- 인플루언서 협업 건 의사결정</span></span>
<span class="line"><span></span></span>
<span class="line"><span>각 안건별로 예상 소요시간도 배분해줘. 총 1시간.</span></span>
<span class="line"><span>회의 초대 메일에 넣을 간단한 안내문도 작성해줘.</span></span></code></pre></div><h2 id="회의-후-회의록-정리" tabindex="-1">회의 후: 회의록 정리 <a class="header-anchor" href="#회의-후-회의록-정리" aria-label="Permalink to &quot;회의 후: 회의록 정리&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>아래 회의 내용을 회의록으로 정리해줘:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[녹음 텍스트 또는 메모를 붙여넣기]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>양식:</span></span>
<span class="line"><span>1. 회의 정보 (일시, 참석자, 장소)</span></span>
<span class="line"><span>2. 주요 논의사항 (안건별로 구분)</span></span>
<span class="line"><span>3. 결정사항 (명확하게)</span></span>
<span class="line"><span>4. 액션 아이템 (담당자, 기한 포함)</span></span>
<span class="line"><span>5. 다음 회의 일정</span></span>
<span class="line"><span></span></span>
<span class="line"><span>액션 아이템은 표로 정리해줘:</span></span>
<span class="line"><span>| 번호 | 할 일 | 담당자 | 기한 | 비고 |</span></span></code></pre></div><h2 id="회의-후-후속-조치" tabindex="-1">회의 후: 후속 조치 <a class="header-anchor" href="#회의-후-후속-조치" aria-label="Permalink to &quot;회의 후: 후속 조치&quot;">​</a></h2><h3 id="참석자-공유-메일" tabindex="-1">참석자 공유 메일 <a class="header-anchor" href="#참석자-공유-메일" aria-label="Permalink to &quot;참석자 공유 메일&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>방금 정리한 회의록을 바탕으로</span></span>
<span class="line"><span>참석자 전원에게 보낼 회의 결과 공유 이메일 써줘.</span></span>
<span class="line"><span>핵심 결정사항과 각자의 액션 아이템을 강조해줘.</span></span></code></pre></div><h3 id="불참자-요약본" tabindex="-1">불참자 요약본 <a class="header-anchor" href="#불참자-요약본" aria-label="Permalink to &quot;불참자 요약본&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>오늘 회의에 참석 못한 김과장님을 위해</span></span>
<span class="line"><span>5줄 요약본을 만들어줘.</span></span>
<span class="line"><span>김과장님이 알아야 할 것만 간추려서.</span></span></code></pre></div><h2 id="회의-중-실시간-노트-활용" tabindex="-1">회의 중: 실시간 노트 활용 <a class="header-anchor" href="#회의-중-실시간-노트-활용" aria-label="Permalink to &quot;회의 중: 실시간 노트 활용&quot;">​</a></h2><p>회의 중에도 Claude를 옆에 두고 실시간으로 활용할 수 있습니다:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>지금부터 회의 내용을 메모할 거야.</span></span>
<span class="line"><span>내가 핵심 키워드만 적어줄 테니, 나중에 회의록으로 정리해줘.</span></span>
<span class="line"><span>시작!</span></span>
<span class="line"><span></span></span>
<span class="line"><span>- 신제품 론칭일 4/15 확정</span></span>
<span class="line"><span>- 마케팅 예산 3000만→2500만 축소</span></span>
<span class="line"><span>- 김대리 SNS 콘텐츠 담당</span></span>
<span class="line"><span>- 다음 미팅 3/25 오전 10시</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>완벽한 문장으로 적을 필요 없어요! 키워드만 던져도 Claude가 구조화된 회의록으로 정리해줍니다.</p></div><h2 id="회의-녹음-텍스트-활용" tabindex="-1">회의 녹음 텍스트 활용 <a class="header-anchor" href="#회의-녹음-텍스트-활용" aria-label="Permalink to &quot;회의 녹음 텍스트 활용&quot;">​</a></h2><p>음성 녹음을 텍스트로 변환한 후 Claude에게 넘기면 더 효율적입니다:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>아래는 오늘 회의 녹음을 텍스트로 변환한 내용이야.</span></span>
<span class="line"><span>(말이 겹치거나 어색한 부분이 있을 수 있어)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[녹음 변환 텍스트 붙여넣기]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>이걸로:</span></span>
<span class="line"><span>1. 깔끔한 회의록 작성</span></span>
<span class="line"><span>2. 핵심 결정사항 3가지</span></span>
<span class="line"><span>3. 각 참석자별 액션 아이템</span></span>
<span class="line"><span>4. 불명확한 부분은 &quot;확인 필요&quot;로 표시</span></span></code></pre></div><h2 id="팀-세션으로-협업하기" tabindex="-1">팀 세션으로 협업하기 <a class="header-anchor" href="#팀-세션으로-협업하기" aria-label="Permalink to &quot;팀 세션으로 협업하기&quot;">​</a></h2><ol><li><strong>팀 세션 만들기</strong> — Cowork에서 &quot;새 팀 세션&quot;을 만들면 동료를 초대할 수 있습니다.</li><li><strong>함께 아이디어 발전시키기</strong> — &quot;우리 팀 워크숍 프로그램 아이디어를 5개 제안해줘&quot; → 팀원들이 실시간으로 의견을 추가</li><li><strong>결과물 함께 다듬기</strong> — Claude가 만든 초안을 팀원들이 보면서 실시간 수정 요청</li></ol>`,20)])])}const b=s(l,[["render",t]]);export{u as __pageData,b as default};
